    "işlemiştir": { root: "İş", translation: "drejt / te Punë", explanation: "İş (Punë) + le (me) + miş (paska) + tir (është)\n\nShënim: Aktivitet, profesion ose detyrë." },
    "kalabilmek": { root: "Kalmak", translation: "mund të ngelësh (në provim)", explanation: "Kalmak (Të ngelësh (në provim)) + abil (mund të) + mek (të)" },
    "kalabilmekiçin": { root: "Kalmak", translation: "mund të ngelësh (në provim)", explanation: "Kalmak (Të ngelësh (në provim)) + abil (mund të) + m (imi / ime) + e (drejt / te) + ki (që është në / i/e) + çi (bërës i/e) + n (yti / jote)" },
    "kaldırmakiçin": { root: "kaldırmak", translation: "heq / ngre / eliminoj", explanation: "kaldırmak (heq / ngre / eliminoj) + m (imi / ime) + a (drejt / te) + ki (që është në / i/e) + çi (bërës i/e) + n (yti / jote)\n\nShënim: Rrënja: kaldır. Mund të përdoret për të hequr pengesat ose për të ngritur diçka peshë." },
    "kalın": { root: "Kalmak", translation: "ngelësh (në provim)", explanation: "Kalmak (Të ngelësh (në provim)) + ın (i/e (gjini))" },
    "kalınünlüler": { root: "Kalmak", translation: "ngelësh (në provim)", explanation: "Kalmak (Të ngelësh (në provim)) + ı ((kallëzore)) + nün (i/e (gjini)) + lü (me) + ler (shumës)" },
    "kanıtlamıştır": { root: "Kanıtlamak", translation: "Vërtetoj / Provon (në të shkuarën)", explanation: "Kanıtlamak (Vërtetoj / Provon) + mış (paska) + tır (është)" },
    "karşılaşabileceğini": { root: "Karşılaşmak", translation: "mund të do të Përballem / Ndeshem / Takohem", explanation: "Karşılaşmak (Përballem / Ndeshem / Takohem) + abil (mund të) + eceğ (do të) + in (ju (urdhërore)) + i ((kallëzore))\n\nShënim: Takohem me dikë ose ndeshem me një problem." },
    "karşılaştığımız": { root: "Karşılaşmak", translation: "Përballem / Ndeshem / Takohem (në të shkuarën)", explanation: "Karşılaşmak (Përballem / Ndeshem / Takohem) + tığ (që ka) + ım (unë / jam) + ız (ne / jemi)\n\nShënim: Takohem me dikë ose ndeshem me një problem." },
    "kaybetmiş": { root: "Kaybetmek", translation: "Humb", explanation: "Kaybetmek (Humb) + miş (paska)" },
    "kelimeler": { root: "Kelime", translation: "Fjala", explanation: "Kelime (Fjalë) + ler (shumës)\n\nShënim: Njësi kuptimplote e gjuhës." },
    "kelimelerin": { root: "Kelime", translation: "Fjala", explanation: "Kelime (Fjalë) + ler (shumës) + in (i/e (gjini))\n\nShënim: Njësi kuptimplote e gjuhës." },
    "kendimize": { root: "Kendi", translation: "drejt / te Vetë / Vete", explanation: "Kendi (Vetë / Vete) + m (imi / ime) + iz (ne / jemi) + e (drejt / te)\n\nShënim: Përemër vetvetor (kendi, kendim, kendine, etc.)." },
    "kendimizeinanmalıyız": { root: "Kendi", translation: "drejt / te Vetë / Vete", explanation: "Kendi (Vetë / Vete) + m (imi / ime) + iz (ne / jemi) + e (drejt / te) + in (ju (urdhërore)) + an (që) + malı (duhet të) + yız (ne / jemi)\n\nShënim: Përemër vetvetor (kendi, kendim, kendine, etc.)." },
    "kendimizi": { root: "Kendi", translation: "Vetë / Vete", explanation: "Kendi (Vetë / Vete) + m (imi / ime) + iz (ne / jemi) + i ((kallëzore))\n\nShënim: Përemër vetvetor (kendi, kendim, kendine, etc.)." },
    "kendine": { root: "Kendi", translation: "drejt / te Vetë / Vete", explanation: "Kendi (Vetë / Vete) + n (yti / jote) + e (drejt / te)\n\nShënim: Përemër vetvetor (kendi, kendim, kendine, etc.)." },
    "kolaydır": { root: "Kolay", translation: "I lehtë / Kolaj", explanation: "Kolay (I lehtë / Kolaj) + dır (është)" },
