    "lazımdır": { root: "Lazım", translation: "I nevojshëm / Duhet", explanation: "Lazım (I nevojshëm / Duhet) + dır (është)\n\nShënim: Diçka që është e nevojshme (lazım olmak = duhet)." },
    "mirassadece": { root: "Miras", translation: "në / tek Trashëgimi / Miras", explanation: "Miras (Trashëgimi / Miras) + sa (nëse) + de (në / tek) + ce (sipas / për / si)" },
    "mücadeleeden": { root: "mücadele", translation: "drejt / te luftë / përpjekje / betejë", explanation: "mücadele (luftë / përpjekje / betejë) + e (drejt / te) + den (prej / nga)\n\nShënim: Huazim i përbashkët me origjinë arabe (muxhadele), tregon përpjekjen ose luftën ndaj sfidave." },
    "müzikle": { root: "Müzik", translation: "drejt / te Muzikë", explanation: "Müzik (Muzikë) + le (me)" },
    "olan": { root: "Olmak", translation: "Bëhem / Ekzistoj / Ndodh", explanation: "Olmak (Bëhem / Ekzistoj / Ndodh) + an (që)\n\nShënim: Folje kryesore ose ndihmëse." },
    "olanuzun": { root: "Olmak", translation: "Bëhem / Ekzistoj / Ndodh", explanation: "Olmak (Bëhem / Ekzistoj / Ndodh) + an (që) + uz (ne / jemi) + un (ju (urdhërore))\n\nShënim: Folje kryesore ose ndihmëse." },
    "olarak": { root: "Olmak", translation: "Bëhem / Ekzistoj / Ndodh", explanation: "Olmak (Bëhem / Ekzistoj / Ndodh) + arak (duke)\n\nShënim: Folje kryesore ose ndihmëse." },
    "olsun": { root: "Olmak", translation: "Bëhem / Ekzistoj / Ndodh", explanation: "Olmak (Bëhem / Ekzistoj / Ndodh) + sun (ti je / je)\n\nShënim: Folje kryesore ose ndihmëse." },
    "olursa": { root: "Olmak", translation: "Bëhem / Ekzistoj / Ndodh", explanation: "Olmak (Bëhem / Ekzistoj / Ndodh) + u ((kallëzore)) + r (zakonisht) + sa (nëse)\n\nShënim: Folje kryesore ose ndihmëse." },
    "onları": { root: "Onlar", translation: "Ata / Ato", explanation: "Onlar (Ata / Ato) + ı ((kallëzore))\n\nShënim: Përemër vetor i vetës së tretë shumës." },
    "onunen": { root: "Onun", translation: "I/e atij / asaj", explanation: "Onun (I/e atij / asaj) + en (që)\n\nShënim: Gjenitivi i 'o'." },
    "onuneserlerini": { root: "Onun", translation: "drejt / te I/e atij / asaj (shumës)", explanation: "Onun (I/e atij / asaj) + e (drejt / te) + se (nëse) + r (zakonisht) + ler (shumës) + in (ju (urdhërore)) + i ((kallëzore))\n\nShënim: Gjenitivi i 'o'." },
    "pratikyapmış": { root: "pratik yapmak", translation: "ushtrohem / bëj praktikë", explanation: "pratik yapmak (ushtrohem / bëj praktikë) + mış (paska)\n\nShënim: Folje e përbërë me foljen ndihmëse \"yapmak\"." },
    "ruhunun": { root: "Ruh", translation: "Shpirt / Ruh", explanation: "Ruh (Shpirt / Ruh) + un (ju (urdhërore)) + un (ju (urdhërore))\n\nShënim: Pjesa jomateriale dhe e pavdekshme e njeriut; gjendje shpirtërore." },
    "ruhununda": { root: "Ruh", translation: "në / tek Shpirt / Ruh", explanation: "Ruh (Shpirt / Ruh) + un (ju (urdhërore)) + un (ju (urdhërore)) + da (në / tek)\n\nShënim: Pjesa jomateriale dhe e pavdekshme e njeriut; gjendje shpirtërore." },
    "sanata": { root: "Sana", translation: "në / tek Të / Ty / Tek ti", explanation: "Sana (Të / Ty / Tek ti) + ta (në / tek)\n\nShënim: Dativi i 'sen' (ti)." },
    "sanatatutunmasını": { root: "Sana", translation: "në / tek Të / Ty / Tek ti", explanation: "Sana (Të / Ty / Tek ti) + ta (në / tek) + t (të shkuar) + u ((kallëzore)) + t (të shkuar) + un (ju (urdhërore)) + m (imi / ime) + a (drejt / te) + sın (ti je / je) + ı ((kallëzore))\n\nShënim: Dativi i 'sen' (ti)." },
    "sanatçılardan": { root: "Sanatçı", translation: "në / tek Artist / Artiste (shumës)", explanation: "Sanatçı (Artist / Artiste) + lar (shumës) + dan (prej / nga)\n\nShënim: Personi që merret me art." },
