    "simgesidir": { root: "simge", translation: "simbol", explanation: "simge (simbol) + si (i/e tij/saj) + dir (është)\n\nShënim: Sinonim i fjalës ndërkombëtare \"sembol\"." },
    "söyler": { root: "Söylemek", translation: "Them / Këndoj", explanation: "Söylemek (Them / Këndoj) + r (zakonisht)\n\nShënim: Them diçka ose këndoj një këngë." },
    "söylerkendimizi": { root: "Söylemek", translation: "Them / Këndoj", explanation: "Söylemek (Them / Këndoj) + r (zakonisht) + ken (kur / ndërsa) + d (të shkuar) + im (unë / jam) + iz (ne / jemi) + i ((kallëzore))\n\nShënim: Them diçka ose këndoj një këngë." },
