    "telaffuzu": { root: "Telaffuz", translation: "Shqiptim", explanation: "Telaffuz (Shqiptim) + u ((kallëzore))\n\nShënim: Mënyra se si nxirren tingujt e një fjalë me gojë." },
    "temaları": { root: "Tema", translation: "Tema", explanation: "Tema (Temë) + lar (shumës) + ı ((kallëzore))\n\nShënim: Mendimi kryesor ose subjekti i një vepre." },
    "temsilcilerinden": { root: "Temsilci", translation: "në / tek Përfaqësues (shumës)", explanation: "Temsilci (Përfaqësues) + ler (shumës) + in (ju (urdhërore)) + den (prej / nga)\n\nShënim: Person që përfaqëson një grup, shtet ose lëvizje." },
