    "türkçeye": { root: "Türkçe", translation: "drejt / te Turqisht", explanation: "Türkçe (Turqisht) + ye (drejt / te)\n\nShënim: Gjuha turke." },
    "ulaşmakiçin": { root: "Ulaşmak", translation: "Mbërrij / Arrij te", explanation: "Ulaşmak (Mbërrij / Arrij te) + m (imi / ime) + a (drejt / te) + ki (që është në / i/e) + çi (bërës i/e) + n (yti / jote)" },
    "ustasanatçılardan": { root: "Usta", translation: "drejt / te Mjeshtër / Usta", explanation: "Usta (Mjeshtër / Ustë) + sa (nëse) + n (yti / jote) + a (drejt / te) + t (të shkuar) + çı (bërës i/e) + lar (shumës) + dan (prej / nga)\n\nShënim: Person i kualifikuar." },
    "uyumu": { root: "uymak", translation: "respektoj / ndjek", explanation: "uymak (respektoj / ndjek) + um (imi / ime) + u ((kallëzore))\n\nShënim: Kuptimi: të ndjekësh ose zbatosh rregullat, ligjet ose këshillat." },
    "vardır": { root: "Var", translation: "Ka / Ekziston", explanation: "Var (Ka / Ekziston) + dır (është)\n\nShënim: Përdoret për të shprehur ekzistencën e diçkaje." },
    "vokaluyumu": { root: "Vokal", translation: "Vokal / Zanor / Zanore", explanation: "Vokal (Vokal / Zanor / Zanore) + u ((kallëzore)) + yum (unë / jam) + u ((kallëzore))\n\nShënim: Tingull zanor ose që lidhet me zërin." },
    "yapılır": { root: "yapılmak", translation: "bëhet / realizohet", explanation: "yapılmak (bëhet / realizohet) + ır (zakonisht)\n\nShënim: Forma pasive e foljes \"yapmak\" (bëj)." },
    "yazıldığı": { root: "yazılmak", translation: "shkruhet (në të shkuarën)", explanation: "yazılmak (shkruhet) + dığ (që ka) + ı ((kallëzore))\n\nShënim: Forma pasive e foljes \"yazmak\" (shkruaj)." },
