    "yola": { root: "Yol", translation: "drejt / te Rrugë / Udhë", explanation: "Yol (Rrugë / Udhë) + a (drejt / te)" },
    "yolculukta": { root: "Yolculuk", translation: "në / tek Udhëtim", explanation: "Yolculuk (Udhëtim) + ta (në / tek)\n\nShënim: Veprimi i udhëtimit." },
    "yolculuğunu": { root: "Yolculuk", translation: "Udhëtim", explanation: "Yolculuk (Udhëtim) + un (ju (urdhërore)) + u ((kallëzore))\n\nShënim: Veprimi i udhëtimit." },
    "yolculuğunuanlatır": { root: "Yolculuk", translation: "Udhëtim", explanation: "Yolculuk (Udhëtim) + un (ju (urdhërore)) + u ((kallëzore)) + an (që) + la (me) + tır (është)\n\nShënim: Veprimi i udhëtimit." },
    "yoldayım": { root: "Yol", translation: "në / tek Rrugë / Udhë", explanation: "Yol (Rrugë / Udhë) + da (në / tek) + yım (unë / jam)" },
    "yoldayıminsanın": { root: "Yol", translation: "në / tek Rrugë / Udhë", explanation: "Yol (Rrugë / Udhë) + da (në / tek) + yım (unë / jam) + in (ju (urdhërore)) + sa (nëse) + n (yti / jote) + ın (ju (urdhërore))" },
