    "yüzünden": { root: "Yüz", translation: "në / tek Qind / Fytyrë", explanation: "Yüz (Qind / Fytyrë) + ün (ju (urdhërore)) + den (prej / nga)" },
    "zamanda": { root: "Zaman", translation: "në / tek Kohë / Zaman", explanation: "Zaman (Kohë / Zaman) + da (në / tek)" },
    "zihinde": { root: "Zihin", translation: "në / tek Mendje / Zotësi mendore", explanation: "Zihin (Mendje / Zotësi mendore) + de (në / tek)\n\nShënim: Kapaciteti për të menduar." },
    "zorluklarına": { root: "zorluk", translation: "drejt / te vështirësi (shumës)", explanation: "zorluk (vështirësi) + lar (shumës) + ın (ju (urdhërore)) + a (drejt / te)\n\nShënim: Nga mbiemri \"zor\" (i vështirë) me prapashtesën emërore \"-luk\"." },
    "zorundakalmıştır": { root: "zorunda kalmak", translation: "detyrohem (në të shkuarën)", explanation: "zorunda kalmak (detyrohem) + mış (paska) + tır (është)\n\nShënim: Lidhje foljore me foljen ndihmëse \"kalmak\" dhe emrin \"zorunda\" (në detyrim)." },
    "çalmayı": { root: "çalmak", translation: "luaj / bie (instrumentit)", explanation: "çalmak (luaj / bie (instrumentit)) + m (imi / ime) + a (drejt / te) + yı ((kallëzore))\n\nShënim: Gjithashtu do të thotë vjedh ose trokas." },
    "çalışması": { root: "Çalışmak", translation: "Punoj / Studioj", explanation: "Çalışmak (Punoj / Studioj) + m (imi / ime) + a (drejt / te) + sı (i/e tij/saj)" },
    "ölümüne": { root: "Ölüm", translation: "drejt / te Vdekje", explanation: "Ölüm (Vdekje) + ün (ju (urdhërore)) + e (drejt / te)\n\nShënim: Mbarimi i jetës." },
    "önemlidir": { root: "Önemli", translation: "I rëndësishëm", explanation: "Önemli (I rëndësishëm) + dir (është)\n\nShënim: Që ka rëndësi të madhe." },
    "önemlidirdüzenli": { root: "Önemli", translation: "drejt / te I rëndësishëm", explanation: "Önemli (I rëndësishëm) + dir (është) + d (të shkuar) + üz (ne / jemi) + e (drejt / te) + n (yti / jote) + li (me)\n\nShënim: Që ka rëndësi të madhe." },
    "öğrenmesi": { root: "öğrenim", translation: "drejt / te shkollim / studim", explanation: "öğrenim (shkollim / studim) + e (drejt / te) + si (i/e tij/saj)\n\nShënim: Rrjedh nga folja \"öğrenmek\" (mësoj)." },
    "öğrenmiştir": { root: "Öğrenmek", translation: "Mësoj (marr dije) (në të shkuarën)", explanation: "Öğrenmek (Mësoj (marr dije)) + miş (paska) + tir (është)" },
    "ünlüeserlerinden": { root: "Ünlü", translation: "drejt / te Zanore / I famshëm (shumës)", explanation: "Ünlü (Zanore / I famshëm) + e (drejt / te) + se (nëse) + r (zakonisht) + ler (shumës) + in (ju (urdhërore)) + den (prej / nga)\n\nShënim: Tingull zanor; person i njohur dhe i famshëm." },
    "ünlüler": { root: "Ünlü", translation: "Zanore / I famshëm (shumës)", explanation: "Ünlü (Zanore / I famshëm) + ler (shumës)\n\nShënim: Tingull zanor; person i njohur dhe i famshëm." },
    "ünlülerise": { root: "Ünlü", translation: "Zanore / I famshëm (shumës)", explanation: "Ünlü (Zanore / I famshëm) + ler (shumës) + i ((kallëzore)) + se (nëse)\n\nShënim: Tingull zanor; person i njohur dhe i famshëm." },
