    "anlaşırsınız": { root: "anlaşmak", translation: "merrem vesh / bie dakord", explanation: "anlaşmak (merrem vesh / bie dakord) + ır (zakonisht) + sınız (ju jeni)\n\nShënim: Nga folja \"anlamak\" (kuptoj). Kuptimi: të kuptoheni reciprokisht." },
    "anılar": { root: "Anı", translation: "Kujtim (shumës)", explanation: "Anı (Kujtim) + lar (shumës)\n\nShënim: Kujtim nga e kaluara." },
