    "ardından": { root: "Aramak", translation: "Kërkoj / Thërras (në telefon)", explanation: "Aramak (Kërkoj / Thërras (në telefon)) + d (të shkuar) + ın (ju (urdhërore)) + dan (prej / nga)\n\nShënim: Kërkoj diçka ose thërras dikë në telefon." },
    "arkadaşları": { root: "Arkadaş", translation: "Mik / Shok (shumës)", explanation: "Arkadaş (Mik / Shok) + lar (shumës) + ı ((kallëzore))" },
    "artar": { root: "Aramak", translation: "Kërkoj / Thërras (në telefon)", explanation: "Aramak (Kërkoj / Thërras (në telefon)) + t (të shkuar) + ar (zakonisht)\n\nShënim: Kërkoj diçka ose thërras dikë në telefon." },
    "atar": { root: "Atmak", translation: "hedhësh / hedh / nënshkruash", explanation: "Atmak (Të hedhësh / hedh / nënshkruash) + a (drejt / te) + r (zakonisht)\n\nShënim: Largimi i diçkaje me forcë nga dora; hedhja e një nënshkrimi (imza atmak)." },
