    "ayırabiliyorum": { root: "Ay", translation: "Muaj / Hënë", explanation: "Ay (Muaj / Hënë) + ır (zakonisht) + abil (mund të) + iyor (po) + um (unë / jam)" },
    "açılır": { root: "Açmak", translation: "Hap / Ndiz (p.sh. dritën)", explanation: "Açmak (Hap / Ndiz (p.sh. dritën)) + ıl (pësore) + ı ((kallëzore)) + r (zakonisht)" },
